1	import { EventEmitter } from "node:events";
2	import type { AgentDefinitionId } from "@superset/shared/agent-catalog";
3	import type { TerminalAgentBinding, TerminalAgentId } from "./types";
4	
5	interface RecordEventInput {
6		terminalId: string;
7		workspaceId: string;
8		eventType: string;
9		agentId?: TerminalAgentId;
10		agentSessionId?: string;
11		definitionId?: AgentDefinitionId;
12		occurredAt: number;
13	}
14	
15	export interface TerminalAgentBindingListFilter {
16		agentId?: TerminalAgentId;
17		definitionId?: AgentDefinitionId;
18	}
19	
20	const EXIT_EVENT_TYPES = new Set(["Detached", "exit", "error"]);
21	
22	export interface TerminalAgentBindingPersistence {
23		load(): TerminalAgentBinding[];
24		upsert(binding: TerminalAgentBinding): void;
25		delete(terminalId: string): void;
26		/**
27		 * Liveness-joined reads (session `active` + workspace-owned). When
28		 * provided, the store serves list/find from here so dead-terminal
29		 * bindings are unrepresentable; the in-memory map then only backs
30		 * `get()` (the fresh-launch wait path).
31		 */
32		listLiveByWorkspace?(
33			workspaceId: string,
34			filter?: TerminalAgentBindingListFilter,
35		): TerminalAgentBinding[];
36		findLiveActive?(
37			workspaceId: string,
38			agentId: TerminalAgentId,
39			definitionId?: AgentDefinitionId,
40		): TerminalAgentBinding | undefined;
41	}
42	
43	/**
44	 * In-process tracker for which agent is alive in which terminal. Populated
45	 * by the hook receiver, drained on terminal exit, and optionally restored
46	 * from host-local persistence across host-service restarts.
47	 *
48	 * Emits `"change"` with the affected workspaceId after every mutation.
49	 */
50	export class TerminalAgentStore extends EventEmitter {
51		private readonly byTerminal = new Map<string, TerminalAgentBinding>();
52		private readonly persistence: TerminalAgentBindingPersistence | undefined;
53	
54		constructor(persistence?: TerminalAgentBindingPersistence) {
55			super();
56			this.persistence = persistence;
57	
58			for (const binding of persistence?.load() ?? []) {
59				this.byTerminal.set(binding.terminalId, binding);
60			}
61		}
62	
63		recordEvent(input: RecordEventInput): void {
64			const {
65				terminalId,
66				workspaceId,
67				eventType,
68				agentId,
69				agentSessionId,
70				definitionId,
71				occurredAt,
72			} = input;
73	
74			if (EXIT_EVENT_TYPES.has(eventType)) {
75				this.deleteTerminal(terminalId);
76				return;
77			}
78	
79			const existing = this.byTerminal.get(terminalId);
80			if (!agentId && !existing) return;
81	
82			const nextAgentId = agentId ?? existing?.agentId;
83			if (!nextAgentId) return;
84	
85			// Only inherit identity metadata when agentId hasn't changed; otherwise
86			// a swap event that omits agentSessionId/definitionId would inherit the
87			// prior agent's values and corrupt definitionId-filtered reads.
88			const prior =
89				existing !== undefined && existing.agentId === nextAgentId
90					? existing
91					: undefined;
92	
93			const sessionChanged =
94				prior !== undefined &&
95				agentSessionId !== undefined &&
96				prior.agentSessionId !== agentSessionId;
97	
98			const next: TerminalAgentBinding = {
99				terminalId,
100				workspaceId,
101				agentId: nextAgentId,
102				agentSessionId: agentSessionId ?? prior?.agentSessionId,
103				definitionId: definitionId ?? prior?.definitionId,
104				startedAt:
105					prior !== undefined && !sessionChanged ? prior.startedAt : occurredAt,
106				lastEventAt: occurredAt,
107				lastEventType: eventType,
108			};
109	
110			this.byTerminal.set(terminalId, next);
111			this.persistence?.upsert(next);
112			this.emit("change", workspaceId);
113		}
114	
115		markTerminalExited(terminalId: string): void {
116			this.deleteTerminal(terminalId);
117		}
118	
119		get(terminalId: string): TerminalAgentBinding | undefined {
120			return this.byTerminal.get(terminalId);
121		}
122	
123		/**
124		 * (AUTO-RESUME) How many live terminals are bound to this agent session id. >1 means
125		 * the same conversation is open/resumed in multiple terminals, so an auto-resume can't
126		 * unambiguously pick the right target and must refuse.
127		 */
128		countByAgentSessionId(agentSessionId: string): number {
